## 2. Data structures to keep per‑binding state

```cpp
// ---------- binding_subscriptions.hpp ----------
#pragma once

#include <esp_err.h>
#include <esp_matter_client.h>
#include <app/ConcreteAttributePath.h>
#include <app/ReadClient.h>
#include <platform/CHIPDeviceLayer.h>
#include <map>
#include <memory>
#include <mutex>

namespace shade {

/* A tiny struct that owns everything needed for a single subscription */
struct Subscription {
    uint16_t local_ep;          // our endpoint (root = 0)
    uint16_t remote_ep;         // endpoint on the remote device
    uint64_t remote_node_id;    // node id of the remote device
    uint8_t fabric_index;       // fabric we are bound to
    chip::DeviceProxy *peer;    // CASE session handle (owned by us)
    std::unique_ptr<chip::ReadClient> read_client; // subscription object
};

/* Global singleton that tracks all active subscriptions */
class SubscriptionManager {
public:
    static SubscriptionManager &Instance()
    {
        static SubscriptionManager s;
        return s;
    }

    /* Called from the binding‑changed callback when we have decided to accept a binding */
    esp_err_t AddBinding(const chip::Binding::BindingEntry &entry);

    /* Called when a binding entry disappears (user removes it or a remote node goes offline) */
    void RemoveBinding(const chip::Binding::BindingEntry &entry);

    /* Helper to look up a subscription by the unique key (fabric+node+endpoint) */
    Subscription *Find(const chip::Binding::BindingEntry &key);

private:
    SubscriptionManager() = default;
    ~SubscriptionManager() = default;
    SubscriptionManager(const SubscriptionManager &) = delete;
    SubscriptionManager &operator=(const SubscriptionManager &) = delete;

    std::mutex m_mutex;
    /* key = (fabric<<48 | node_id<<16 | remote_ep)  – fits in a uint64_t */
    std::map<uint64_t, std::unique_ptr<Subscription>> m_subs;
};

} // namespace shade
```

*Why a map?*  
The Binding table does **not** give you a handle that survives a reboot, so we need a deterministic key that we can recompute from the entry fields. The 64‑bit key above is stable across reboots as long as the binding entry stays the same.

