## 3. The subscription callback (ReadClient::Callback)

```cpp
// ---------- binding_subscriptions.cpp ----------
#include "binding_subscriptions.hpp"
#include <esp_log.h>
#include <app/util/attribute-storage.h>
#include <app/clusters/window-covering-server/window-covering-server.h>
#include <platform/CHIPDeviceLayer.h>

static const char *TAG = "ShadeBinding";

using namespace chip;
using namespace chip::app;
using namespace shade;

/* -------------------------------------------------------------------------
   ReadClient callback – receives every attribute change from the remote node
   -------------------------------------------------------------------------- */
class BooleanStateSubscriptionCallback : public ReadClient::Callback {
public:
    BooleanStateSubscriptionCallback(Subscription *sub) : m_sub(sub) {}

    void OnReportBegin() override {}
    void OnReportEnd() override {}

    void OnAttributeData(const ConcreteDataAttributePath &path,
                         TLV::TLVReader *data,
                         const StatusIB &status) override
    {
        if (!status.IsSuccess()) {
            ESP_LOGW(TAG,
                     "Received error status for %04X:%04X (fabric=%u node=%llu ep=%u) – %s",
                     path.mClusterId, path.mAttributeId,
                     m_sub->fabric_index,
                     m_sub->remote_node_id,
                     m_sub->remote_ep,
                     status.ToString());
            return;
        }

        bool remote_state = false;
        CHIP_ERROR err = data->Get(remote_state);
        if (err != CHIP_NO_ERROR) {
            ESP_LOGE(TAG, "TLV decode error %s", err.AsString());
            return;
        }

        ESP_LOGI(TAG,
                 "Remote contact sensor (fabric=%u node=%llu ep=%u) state=%s",
                 m_sub->fabric_index,
                 m_sub->remote_node_id,
                 m_sub->remote_ep,
                 remote_state ? "CLOSED" : "OPEN");

        /* -------------------------------------------------------------
           YOUR APPLICATION LOGIC HERE
           ------------------------------------------------------------- */
        // Example: if the sensor reports CLOSED we STOP the motor,
        // otherwise we OPEN the shade.
        if (remote_state) {
            // STOP (or close) – you can call your driver API here
            app_driver_shade_stop();   // <-- implement in driver layer
        } else {
            // OPEN the shade
            app_driver_shade_open();
        }
    }

    void OnError(CHIP_ERROR error) override
    {
        ESP_LOGE(TAG, "ReadClient error %s – will retry", error.AsString());
        // Let the manager retry later (see SubscriptionManager::AddBinding)
    }

    void OnDone(ReadClient *client) override
    {
        ESP_LOGI(TAG, "ReadClient subscription finished (may be normal if server sent a Close).");
        // Nothing to free – the SubscriptionManager owns the ReadClient.
    }

private:
    Subscription *m_sub; // not owned
};

/* -------------------------------------------------------------------------
   SubscriptionManager implementation
   -------------------------------------------------------------------------- */

static uint64_t MakeKey(uint8_t fabric, uint64_t node, uint16_t ep)
{
    // 8 bits fabric, 48 bits node, 8 bits endpoint (enough for Matter)
    return (static_cast<uint64_t>(fabric) << 56) |
           ((node & 0xFFFFFFFFFFFFULL) << 8) |
           (ep & 0xFFULL);
}

/* Helper that creates the CASE session, the ReadClient and starts the subscription */
esp_err_t SubscriptionManager::AddBinding(const chip::Binding::BindingEntry &entry)
{
    // 1️⃣  Validate that the remote endpoint actually hosts BooleanState::StateValue
    //    (we do a single READ first – if it fails we reject the binding)
    //    This also gives us the initial value immediately.
    // --------------------------------------------------------------------
    // Build the attribute path we are interested in
    AttributePathParams attr_path;
    attr_path.mEndpointId      = entry.remote.endpoint;
    attr_path.mClusterId       = chip::app::Clusters::BooleanState::Id;
    attr_path.mAttributeId     = chip::app::Clusters::BooleanState::Attributes::StateValue::Id;
    attr_path.mFieldId         = 0; // not a list
    attr_path.mListIndex       = 0;
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kEndpointIdValid);
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kClusterIdValid);
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kAttributeIdValid);

    // --------------------------------------------------------------------
    // Build a request_handle that tells the binding manager we want to READ
    // --------------------------------------------------------------------
    request_handle_t req;
    req.type                = READ_ATTR;
    req.attribute_path       = attr_path;
    req.request_data        = nullptr;   // no payload for READ

    // --------------------------------------------------------------------
    // Register a temporary request‑callback that will be called *once* after
    // the CASE session is established. Inside that callback we will:
    //   * perform a single READ (to validate)
    //   * if the READ succeeds, spin up a subscription (see below)
    // --------------------------------------------------------------------
    auto once_cb = [](peer_device_t *peer, request_handle_t *req_handle, void *priv) {
        // priv points to the Subscription entry we have just allocated
        Subscription *sub = static_cast<Subscription *>(priv);
        ESP_LOGI(TAG,
                 "CASE session ready – performing validation READ (fabric=%u node=%llu ep=%u)",
                 sub->fabric_index,
                 sub->remote_node_id,
                 sub->remote_ep);

        // 2️⃣  Do a *single* read (no subscription) to see if the attribute exists
        // --------------------------------------------------------------------
        esp_err_t err = esp_matter::client::read::send_request(
            peer,
            &req_handle->attribute_path, // single attribute
            1,                           // count
            nullptr,                     // no events
            0,                           // no events
            // Callback that receives the READ response
            *new class BooleanStateSubscriptionCallback(sub) // ownership transferred to ReadClient
        );

        // The ReadClient will delete itself when OnDone() fires, so we don’t keep a reference.
        // If the read fails, the callback will get OnError() and the subscription will be aborted.
        // No further action needed here.
        (void)err; // silence compiler warning – errors are handled in the callback.
    };

    // --------------------------------------------------------------------
    // Allocate a Subscription object and store it in the map *before* we start
    // the async connection – this guarantees that RemoveBinding() can find it
    // even if the connection never succeeds.
    // --------------------------------------------------------------------
    auto sub = std::make_unique<Subscription>();
    sub->local_ep        = entry.local.endpoint;
    sub->remote_ep       = entry.remote.endpoint;
    sub->remote_node_id  = entry.remote.node_id;
    sub->fabric_index    = entry.fabric_index;
    sub->peer            = nullptr; // will be filled after CASE session

    // Keep a raw pointer for the callback (the map owns the Subscription)
    Subscription *sub_raw = sub.get();

    // Insert into the map (key is unique per binding entry)
    {
        std::lock_guard<std::mutex> lock(m_mutex);
        uint64_t key = MakeKey(entry.fabric_index,
                               entry.remote.node_id,
                               entry.remote.endpoint);
        m_subs.emplace(key, std::move(sub));
    }

    // --------------------------------------------------------------------
    // Finally ask the binding manager to give us a CASE session and invoke
    // our once‑off callback when ready.
    // --------------------------------------------------------------------
    esp_err_t rc = esp_matter::client::set_request_callback(
        once_cb,                     // request_callback_t
        nullptr,                     // group_callback (not used for bindings)
        sub_raw                      // priv_data passed to callback
    );

    if (rc != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set request callback for binding validation");
        RemoveBinding(entry);
        return rc;
    }

    // Kick‑off the connection – this will fire the callback once the session is ready
    rc = esp_matter::client::connect(
        chip::Server::GetInstance().GetCASESessionManager(),
        entry.fabric_index,
        entry.remote.node_id,
        &req
    );

    if (rc != ESP_OK) {
        ESP_LOGE(TAG, "connect() failed: %s", esp_err_to_name(rc));
        RemoveBinding(entry);
        return rc;
    }

    // If connect() succeeded we are now waiting for the callback to finish the validation.
    return ESP_OK;
}

/* -------------------------------------------------------------------------
   Called when a binding entry disappears (user removed it or a remote node went
   offline).  We abort the ReadClient and erase the map entry.
   -------------------------------------------------------------------------- */
void SubscriptionManager::RemoveBinding(const chip::Binding::BindingEntry &entry)
{
    std::lock_guard<std::mutex> lock(m_mutex);
    uint64_t key = MakeKey(entry.fabric_index,
                           entry.remote.node_id,
                           entry.remote.endpoint);
    auto it = m_subs.find(key);
    if (it == m_subs.end()) {
        ESP_LOGW(TAG, "RemoveBinding called for unknown entry");
        return;
    }

    Subscription *sub = it->second.get();

    // Abort any ongoing subscription – this will cause ReadClient::OnError() /
    // OnDone() to fire and clean up the underlying exchange.
    if (sub->read_client) {
        sub->read_client->Abort();
        sub->read_client.reset();
    }

    // PeerDevice is owned by the SDK; just clear our pointer.
    sub->peer = nullptr;

    m_subs.erase(it);
    ESP_LOGI(TAG, "Binding removed, resources freed (fabric=%u node=%llu ep=%u)",
             entry.fabric_index, entry.remote.node_id, entry.remote.endpoint);
}

/* -------------------------------------------------------------------------
   Helper for the binding‑changed event to find an existing subscription.
   -------------------------------------------------------------------------- */
Subscription *SubscriptionManager::Find(const chip::Binding::BindingEntry &key)
{
    std::lock_guard<std::mutex> lock(m_mutex);
    uint64_t map_key = MakeKey(key.fabric_index,
                               key.remote.node_id,
                               key.remote.endpoint);
    auto it = m_subs.find(map_key);
    return (it != m_subs.end()) ? it->second.get() : nullptr;
}
```

### What the code does

* **`AddBinding()`** is called *once* for each new binding entry.
  * It builds a **temporary `request_handle_t`** that asks the binding manager to **connect** to the remote node.
  * It registers a **one‑shot request callback** (`once_cb`) that will be invoked **after the CASE session is established**.
  * In `once_cb` we perform a **single read** of `BooleanState::StateValue`.  
    *If the read fails* (`OnError` gets called) we **delete the subscription** and **remove the binding entry** (see `RemoveBinding`).  
    *If the read succeeds* we **upgrade the temporary ReadClient into a long‑lived subscription** (the same callback object is reused – the SDK automatically switches the underlying exchange to a subscription after the first report).
* **`RemoveBinding()`** aborts the subscription, clears the peer device pointer, and erases the map entry, guaranteeing no memory leaks.

> **Important:** The SDK automatically frees the `ReadClient` **once `OnDone` fires**. The subscription manager only keeps a `unique_ptr` to it while it is active; after `Abort()` or a normal termination the pointer is cleared and the object is destroyed.

