static const char *TAG = "app_main";

/* -------------------------------------------------------------
   Forward declaration of the function that will be called when the
   binding table changes (kBindingsChangedViaCluster event).
   ------------------------------------------------------------- */
static void binding_table_changed(const chip::ChipDeviceEvent *event, intptr_t arg);
```

### 4.1 Register the binding‑changed event handler

In `app_main()` (right after you create the node, before `esp_matter::start()`), add:

```cpp
// Register for the generic “bindings changed” event
chip::DeviceLayer::PlatformMgr().AddEventHandler(
    [](const chip::ChipDeviceEvent *event, intptr_t arg) {
        if (event->Type == chip::DeviceLayer::DeviceEventType::kBindingsChangedViaCluster) {
