/* -----------------------------------------------------------------
   The heavy‑lifting: this runs every time the binding table changes.
   ----------------------------------------------------------------- */
static void binding_table_changed(const chip::ChipDeviceEvent * /*event*/, intptr_t /*arg*/)
{
    const chip::Binding::BindingTable &table = chip::Server::GetInstance().GetBindingTable();

    // -----------------------------------------------------------------
    // 1️⃣  Process *new* entries
    // -----------------------------------------------------------------
    for (size_t i = 0; i < table.Size(); ++i) {
        const chip::Binding::BindingEntry &entry = table[i];
        if (!entry.IsValid())
            continue;   // empty slot

        // Accept only BooleanState cluster on the remote side
        if (entry.remote.cluster != chip::app::Clusters::BooleanState::Id) {
            ESP_LOGI(TAG,
                     "Skipping binding %zu – remote cluster 0x%04X not BooleanState",
                     i,
                     entry.remote.cluster);
            continue;
        }

        // Already have a subscription?
        if (shade::SubscriptionManager::Instance().Find(entry) != nullptr)
            continue;

        // Optional: reject foreign fabrics
        // if (entry.fabric_index != chip::Server::GetInstance().GetFabricTable().GetPrimaryFabricIndex()) {
        //     ESP_LOGW(TAG, "Rejecting binding from foreign fabric %u", entry.fabric_index);
        //     chip::Server::GetInstance().GetBindingTable().RemoveAt(i);
        //     continue;
        // }

        // Accept – start a subscription
        esp_err_t rc = shade::SubscriptionManager::Instance().AddBinding(entry);
        if (rc != ESP_OK) {
            ESP_LOGE(TAG,
                     "Failed to start subscription for binding %zu: %s",
                     i,
                     esp_err_to_name(rc));
            // Optionally delete the bad entry so the user sees the failure.
            // chip::Server::GetInstance().GetBindingTable().RemoveAt(i);
        }
    }

    // -----------------------------------------------------------------
    // 2️⃣  Clean up any subscriptions whose entry disappeared
    // -----------------------------------------------------------------
    // Build a list of current valid keys
    std::vector<chip::Binding::BindingEntry> current;
    for (size_t i = 0; i < table.Size(); ++i) {
        const auto &e = table[i];
        if (e.IsValid())
            current.push_back(e);
    }

    // Walk the map and remove anything not present any more
    std::vector<chip::Binding::BindingEntry> to_remove;
    {
        std::lock_guard<std::mutex> lock(shade::SubscriptionManager::Instance().m_mutex);
        for (const auto &kv : shade::SubscriptionManager::Instance().m_subs) {
            uint64_t raw = kv.first;
            uint8_t fab   = (raw >> 56) & 0xFF;
            uint64_t nid  = (raw >> 8)  & 0xFFFFFFFFFFFFULL;
            uint16_t ep   = raw & 0xFF;

            bool found = false;
            for (const auto &e : current) {
                if (e.fabric_index == fab && e.remote.node_id == nid && e.remote.endpoint == ep) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                chip::Binding::BindingEntry dead{};
                dead.fabric_index = fab;
                dead.remote.node_id = nid;
                dead.remote.endpoint = ep;
                to_remove.push_back(dead);
            }
        }
    }

    for (const auto &dead : to_remove) {
        shade::SubscriptionManager::Instance().RemoveBinding(dead);
    }
}
```

That’s it – **no other files need to change**. Build and flash the firmware; after commissioning you can use any Matter controller (e.g. Home Assistant, Apple Home, Google Home) to **add a binding**:

1. Open the *Add Binding* UI on the controller.  
2. Choose **your shade device** as the *source* (the endpoint that holds the Binding cluster – endpoint 0).  
3. Choose the **contact‑sensor device** as the *target* and select **BooleanState → StateValue**.  
4. Press *Bind*.

If everything is correct you will see in the log:

