## 1. Header – `binding_subscriptions.hpp`

```cpp
// ---------------------------------------------------------------
// binding_subscriptions.hpp
// ---------------------------------------------------------------
#pragma once

#include <esp_err.h>
#include <esp_matter_client.h>
#include <app/ConcreteAttributePath.h>
#include <app/ReadClient.h>
#include <platform/CHIPDeviceLayer.h>
#include <map>
#include <memory>

namespace chip {
namespace app {
namespace Clusters {
namespace Binding {
struct TableEntry;   // forward‑declare – the real definition lives in CHIP
} // Binding
} // Clusters
} // app
} // chip

namespace shade {

/* -----------------------------------------------------------------
   One subscription – owns everything needed to keep a remote
   BooleanState attribute subscribed.
   ----------------------------------------------------------------- */
struct Subscription {
    uint16_t local_ep;          // our endpoint (normally 0)
    uint16_t remote_ep;         // endpoint on the remote device
    uint64_t remote_node_id;    // node id of the remote device
    uint8_t  fabric_index;      // fabric we are bound to
    chip::DeviceProxy *peer;    // CASE session handle (owned by us)
    std::unique_ptr<chip::ReadClient> read_client; // active subscription
};

/* -----------------------------------------------------------------
   Manager – holds the *current* set of subscriptions.
   ----------------------------------------------------------------- */
class SubscriptionManager {
public:
    /* Get the singleton */
    static SubscriptionManager &Instance()
    {
        static SubscriptionManager s;
        return s;
    }

    /* -----------------------------------------------------------------
       Called for each entry while the caller walks the binding table.
       - `entry` is the current table entry.
       - `new_sub_assemble` is a map that the caller builds on‑the‑fly.
       The function either moves an existing subscription into the map
       or creates a brand‑new one (and starts the subscription).
       Returns ESP_OK on success, otherwise an error.
       ----------------------------------------------------------------- */
    esp_err_t AddBinding(const chip::app::Clusters::Binding::TableEntry &entry,
                         std::map<uint64_t, std::unique_ptr<Subscription>> &new_sub_assemble);

    /* -----------------------------------------------------------------
       Called **once** after the whole table has been processed.
       It removes every subscription that is *not* present in the
       temporary map, then swaps the internal map with the new one.
       ----------------------------------------------------------------- */
    void FinishAdditions(std::map<uint64_t, std::unique_ptr<Subscription>> &new_sub_assemble);

    /* -----------------------------------------------------------------
       Helper used by the manager internally – find a subscription that
       belongs to a specific entry (used only while the manager still
       owns the old map).
       ----------------------------------------------------------------- */
    Subscription *FindExisting(const chip::app::Clusters::Binding::TableEntry &entry);

private:
    SubscriptionManager() = default;
    ~SubscriptionManager() = default;
    SubscriptionManager(const SubscriptionManager &) = delete;
    SubscriptionManager &operator=(const SubscriptionManager &) = delete;

    /* -----------------------------------------------------------------
       The map that holds the *current* live subscriptions.
       Key = (fabric << 56) | (node_id << 8) | remote_endpoint
       ----------------------------------------------------------------- */
    std::map<uint64_t, std::unique_ptr<Subscription>> m_subs;

    /* -----------------------------------------------------------------
       Internal helpers – not part of the public API.
       ----------------------------------------------------------------- */
    static uint64_t MakeKey(uint8_t fabric, uint64_t node, uint16_t ep);
    esp_err_t StartSubscription(Subscription *sub);
    void AbortAndDelete(Subscription *sub);
};
} // namespace shade
```

