## 2. Implementation – `binding_subscriptions.cpp`

```cpp
// ---------------------------------------------------------------
// binding_subscriptions.cpp
// ---------------------------------------------------------------
#include "binding_subscriptions.hpp"
#include <esp_log.h>
#include <app/util/attribute-storage.h>
#include <app/clusters/window-covering-server/window-covering-server.h>
#include <platform/CHIPDeviceLayer.h>

static const char *TAG = "ShadeBinding";

using namespace chip;
using namespace chip::app;
using namespace chip::app::Clusters;
using namespace shade;

/* -----------------------------------------------------------------
   Key construction – matches the layout used in the original code.
   ----------------------------------------------------------------- */
uint64_t SubscriptionManager::MakeKey(uint8_t fabric, uint64_t node, uint16_t ep)
{
    return (static_cast<uint64_t>(fabric) << 56) |
           ((node & 0xFFFFFFFFFFFFULL) << 8) |
           (ep & 0xFFULL);
}

/* -----------------------------------------------------------------
   Look for an existing subscription that matches the entry.
   ----------------------------------------------------------------- */
Subscription *SubscriptionManager::FindExisting(const Binding::TableEntry &entry)
{
    uint64_t key = MakeKey(entry.fabricIndex,
                           entry.remote.nodeId,
                           entry.remote.endpoint);
    auto it = m_subs.find(key);
    return (it != m_subs.end()) ? it->second.get() : nullptr;
}

/* -----------------------------------------------------------------
   Start (or restart) a subscription for a given Subscription object.
   This is exactly the same logic that previously lived in
   SubscriptionManager::AddBinding() – we split it out so that the
   same code can be used for newly‑created subscriptions.
   ----------------------------------------------------------------- */
esp_err_t SubscriptionManager::StartSubscription(Subscription *sub)
{
    // -----------------------------------------------------------------
    // Build the attribute path we want to subscribe to.
    // -----------------------------------------------------------------
    AttributePathParams attr_path;
    attr_path.mEndpointId      = sub->remote_ep;
    attr_path.mClusterId       = BooleanState::Id;
    attr_path.mAttributeId     = BooleanState::Attributes::StateValue::Id;
    attr_path.mFieldId         = 0;
    attr_path.mListIndex       = 0;
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kEndpointIdValid);
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kClusterIdValid);
    attr_path.mFlags.Set(AttributePathParams::FlagValues::kAttributeIdValid);

    // -----------------------------------------------------------------
    // Build a request_handle that tells the binding manager we want a READ
    // (the first report will be a READ, then it automatically upgrades to
    // a subscription).
    // -----------------------------------------------------------------
    request_handle_t req{};
    req.type          = READ_ATTR;
    req.attribute_path = attr_path;
    req.request_data   = nullptr;

    // -----------------------------------------------------------------
    // Register a *one‑shot* request callback that will be invoked once the
    // CASE session is ready. Inside that callback we create a ReadClient that
    // subscribes.
    // -----------------------------------------------------------------
    auto once_cb = [](peer_device_t *peer, request_handle_t *req_handle, void *priv) {
        Subscription *sub = static_cast<Subscription *>(priv);
        ESP_LOGI(TAG,
                 "CASE ready – starting BooleanState subscription (fabric=%u node=%llu ep=%u)",
                 sub->fabric_index,
                 sub->remote_node_id,
                 sub->remote_ep);

        // The ReadClient takes ownership of the callback object.
        auto *cb = new class BooleanStateSubscriptionCallback(sub);

        // The SDK will free the ReadClient once OnDone() fires.
        esp_err_t rc = esp_matter::client::read::send_request(
            peer,
            &req_handle->attribute_path,
            1,                // one attribute path
            nullptr,
            0,
            *cb               // callback (owned)
        );
        (void)rc; // errors are reported via the callback
    };

    // -----------------------------------------------------------------
    // Store a pointer to the subscription in the request‑callback priv data.
    // -----------------------------------------------------------------
    esp_err_t rc = esp_matter::client::set_request_callback(once_cb, nullptr, sub);
    if (rc != ESP_OK) {
        ESP_LOGE(TAG, "set_request_callback failed: %s", esp_err_to_name(rc));
        return rc;
    }

    // -----------------------------------------------------------------
    // Finally ask the binding manager to give us a CASE session.
    // -----------------------------------------------------------------
    rc = esp_matter::client::connect(
        chip::Server::GetInstance().GetCASESessionManager(),
        sub->fabric_index,
        sub->remote_node_id,
        &req);

    if (rc != ESP_OK) {
        ESP_LOGE(TAG,
                 "connect() failed for fabric=%u node=%llu: %s",
                 sub->fabric_index,
                 sub->remote_node_id,
                 esp_err_to_name(rc));
        // Clean up the request‑callback we just installed.
        esp_matter::client::set_request_callback(nullptr, nullptr, nullptr);
    }

    return rc;
}

/* -----------------------------------------------------------------
   Abort a subscription and release its resources.  This is used when a
   binding entry disappears.
   ----------------------------------------------------------------- */
void SubscriptionManager::AbortAndDelete(Subscription *sub)
{
    if (sub->read_client) {
        sub->read_client->Abort();
        sub->read_client.reset();
    }
    sub->peer = nullptr;
}

/* -----------------------------------------------------------------
   Public API – called for every entry while the table is being walked.
   ----------------------------------------------------------------- */
esp_err_t SubscriptionManager::AddBinding(const Binding::TableEntry &entry,
                                          std::map<uint64_t, std::unique_ptr<Subscription>> &new_sub_assemble)
{
    // Build the map key for this entry.
    uint64_t key = MakeKey(entry.fabricIndex,
                           entry.remote.nodeId,
                           entry.remote.endpoint);

    // -------------------------------------------------------------
    // 1️⃣  Does a subscription already exist for this entry?
    // -------------------------------------------------------------
    auto it_old = m_subs.find(key);
    if (it_old != m_subs.end()) {
        // Move the existing unique_ptr into the new map – the manager
        // no longer owns it, the new map does.
        new_sub_assemble.emplace(key, std::move(it_old->second));
        m_subs.erase(it_old);
        ESP_LOGI(TAG,
                 "Re‑using existing subscription for fabric=%u node=%llu ep=%u",
                 entry.fabricIndex,
                 entry.remote.nodeId,
                 entry.remote.endpoint);
        return ESP_OK;
    }

    // -------------------------------------------------------------
    // 2️⃣  No existing subscription – create a fresh one.
    // -------------------------------------------------------------
    auto sub = std::make_unique<Subscription>();
    sub->local_ep       = entry.local.endpoint;   // usually 0 (root)
    sub->remote_ep      = entry.remote.endpoint;
    sub->remote_node_id = entry.remote.nodeId;
    sub->fabric_index   = entry.fabricIndex;
    sub->peer           = nullptr;               // will be filled by CASE

    // Keep a raw pointer for the callback (the map will own the Subscription)
    Subscription *sub_raw = sub.get();

    // Insert into the *temporary* map that the caller is building.
    new_sub_assemble.emplace(key, std::move(sub));

    // -----------------------------------------------------------------
    // Kick off the subscription now – the callback will be stored inside
    // the Subscription object (the ReadClient will own it).
    // -----------------------------------------------------------------
    esp_err_t rc = StartSubscription(sub_raw);
    if (rc != ESP_OK) {
        // Clean up the map entry we just inserted.
        new_sub_assemble.erase(key);
        ESP_LOGE(TAG,
                 "Failed to start subscription for new entry (fabric=%u node=%llu ep=%u): %s",
                 entry.fabricIndex,
                 entry.remote.nodeId,
                 entry.remote.endpoint,
                 esp_err_to_name(rc));
    }
    return rc;
}

/* -----------------------------------------------------------------
   Public API – called **once** after the whole table has been walked.
   It removes everything that stayed in the *old* map but did **not**
   appear in the new map, then swaps the internal map with the new one.
   ----------------------------------------------------------------- */
void SubscriptionManager::FinishAdditions(std::map<uint64_t, std::unique_ptr<Subscription>> &new_sub_assemble)
{
    // -------------------------------------------------------------
    // Anything that is still left in m_subs after the loop is a binding
    // that disappeared → abort it.
    // -------------------------------------------------------------
    for (auto &kv : m_subs) {
        Subscription *sub = kv.second.get();
        ESP_LOGI(TAG,
                 "Binding removed – aborting subscription (fabric=%u node=%llu ep=%u)",
                 sub->fabric_index,
                 sub->remote_node_id,
                 sub->remote_ep);
        AbortAndDelete(sub);
    }

    // Clear the old map – we have already aborted all its entries.
    m_subs.clear();

    // -------------------------------------------------------------
    // The caller’s temporary map now becomes the *new* live set.
    // -------------------------------------------------------------
    m_subs.swap(new_sub_assemble);
    // After the swap, new_sub_assemble is empty (its destructor will do nothing).
}

/* -----------------------------------------------------------------
   Minimal ReadClient callback – identical to the one shown in the
   previous answer, only a tiny change: we store the ReadClient pointer
   inside the Subscription so we can abort it later.
   ----------------------------------------------------------------- */
class BooleanStateSubscriptionCallback : public ReadClient::Callback {
public:
    explicit BooleanStateSubscriptionCallback(Subscription *sub) : m_sub(sub) {}

    void OnReportBegin() override {}
    void OnReportEnd() override {}

    void OnAttributeData(const ConcreteDataAttributePath &path,
                         TLV::TLVReader *data,
                         const StatusIB &status) override
    {
        if (!status.IsSuccess()) {
            ESP_LOGW(TAG,
                     "Remote attribute error (fabric=%u node=%llu ep=%u): %s",
                     m_sub->fabric_index,
                     m_sub->remote_node_id,
                     m_sub->remote_ep,
                     status.ToString());
            return;
        }

        bool remote_state = false;
        CHIP_ERROR err = data->Get(remote_state);
        if (err != CHIP_NO_ERROR) {
            ESP_LOGE(TAG, "TLV decode error: %s", err.AsString());
            return;
        }

        ESP_LOGI(TAG,
                 "Contact sensor (fabric=%u node=%llu ep=%u) state=%s",
                 m_sub->fabric_index,
                 m_sub->remote_node_id,
                 m_sub->remote_ep,
                 remote_state ? "CLOSED" : "OPEN");

        // -----------------------------------------------------------------
        // YOUR APPLICATION LOGIC – replace with your own driver calls.
        // -----------------------------------------------------------------
        if (remote_state) {
            app_driver_shade_stop();   // e.g. stop motor when contact closed
        } else {
            app_driver_shade_open();   // open when contact open
        }
    }

    void OnError(CHIP_ERROR error) override
    {
        ESP_LOGE(TAG,
                 "ReadClient error (fabric=%u node=%llu ep=%u): %s – will retry on next binding scan",
                 m_sub->fabric_index,
                 m_sub->remote_node_id,
                 m_sub->remote_ep,
                 error.AsString());
        // No explicit retry here – the next time the binding table is
        // scanned we will recreate the subscription if it still exists.
    }

    void OnDone(ReadClient *client) override
    {
        ESP_LOGI(TAG,
                 "ReadClient finished (fabric=%u node=%llu ep=%u)",
                 m_sub->fabric_index,
                 m_sub->remote_node_id,
                 m_sub->remote_ep);
        // Store the client pointer so we can abort it later if needed.
        m_sub->read_client.reset(client);
    }

private:
    Subscription *m_sub; // not owned
};
